import "@radix-ui/themes/styles.css";
import { Box, Flex, Link } from "@radix-ui/themes";
import { GitHubLogoIcon, LinkedInLogoIcon, FaceIcon, ImageIcon, SunIcon } from "@radix-ui/react-icons"

const Links = () => {
    return (
        <Box mt="7" id="links">
            <Flex gap="4" direction="row">
                <Link>
                    <GitHubLogoIcon color="white" />
                </Link>
                <Link>
                    <LinkedInLogoIcon color="white" fontSize="5" size = "5" />
                </Link>
            </Flex>
        </Box>
    )
}

export default Links;
